const body = $input.first().json || {};

const lead = {
  full_name: (body.full_name || body.name || 'Valued Client').trim(),
  email: (body.email || '').toLowerCase().trim(),
  phone: (body.phone || body.phone_number || '').replace(/[\s\-().+]/g, '').trim(),
  property_value: body.property_value || body.budget || 'Market Value',
  source: body.source || body.utm_source || 'direct_inquiry',
  submitted_at: new Date().toISOString(),
  lead_id: `lead_${Date.now()}_${Math.floor(Math.random() * 9999).toString().padStart(4, '0')}`
};

const phone_looks_valid = /^[1-9]\d{7,14}$/.test(lead.phone);
const email_looks_valid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(lead.email);

return [{ json: { ...lead, phone_looks_valid, email_looks_valid } }];

const lead = $('Normalize Lead Data').first().json;
const v = $input.first().json || {};

return [{
  json: {
    ...lead,
    phone_verified: v.valid === true,
    phone_is_mobile: (v.type || '').toLowerCase().includes('mobile'),
    phone_carrier: v.carrier?.name || 'Unknown',
    phone_country: v.country?.code || 'Unknown',
    phone_format: v.format?.international || ('+' + lead.phone)
  }
}];

